// ============================================================
// PREPARE conversation log data
// ============================================================
const input = $input.first().json;
const tenant = input.tenant;
if (!tenant || !tenant.business_id) throw new Error('Missing tenant.business_id');

const now = new Date();
const dateStr = now.toISOString().slice(0, 10).replace(/-/g, '');
const convId = input.conversation_id || `CONV_${dateStr}_${Math.floor(Math.random() * 90000) + 10000}`;

return {
  json: {
    business_id:        tenant.business_id,
    order_id:           tenant.order_id || '',
    conversation_id:    convId,
    customer_id:        input.customer_id || input.customer_phone || 'UNKNOWN',
    customer_name:      input.customer_name || '',
    customer_phone:     input.customer_phone || input.customer_id || '',
    customer_message:   input.customer_message || '',
    ai_response:        input.ai_response || '',
    intent:             input.intent || 'general',
    intent_confidence:  parseFloat(input.intent_confidence || 0),
    sentiment_score:    parseInt(input.sentiment_score || 0),
    sentiment_label:    input.sentiment_label || 'Neutral',
    escalated:          input.escalated === true || input.escalated === 'true',
    response_time_sec:  parseFloat(input.response_time_sec || 0),
    input_tokens:       parseInt(input.input_tokens || 0),
    output_tokens:      parseInt(input.output_tokens || 0),
    cost_egp:           parseFloat(input.cost_egp || 0),
    model_used:         input.model_used || 'anthropic/claude-sonnet-4.5',
    channel:            input.channel || 'whatsapp',
    created_at:         now.toISOString()
  }
};

const msg = $('INSERT_MESSAGE').first().json;
return {
  json: {
    success: true,
    message_id: Array.isArray(msg) ? msg[0]?.id : msg?.id,
    conversation_id: $('LOG_CONV_PREPARE').first().json.conversation_id,
    cost_egp: $('LOG_CONV_PREPARE').first().json.cost_egp
  }
};
